  ('generalpolice-94737317-moex-00392', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '下列何者非屬行政處分撤銷之事由？', '["內容不明確", "認定事實錯誤", "應給予當事人陳述意見機會而未給予陳述意見", "救濟期間告知錯誤"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "40162905cbc1", "answer_pdf_sha1": "b681be7ebd22", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00393', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '依民法規定，下列有關贈與人撤銷權之敘述，何者正確？', '["即使是履行道德上義務而為贈與者，只要贈與物之權利未移轉前，贈與人仍得任意撤銷贈與", "受贈人對於贈與人之配偶，只要有過失侵害行為，依刑法有處罰之明文者，贈與人得撤銷其贈與", "受贈人對贈與人有扶養義務而不履行，但贈與人對受贈人已為宥恕之表示者，贈與人之撤銷權消滅", "贈與人因被受贈人詐欺而為贈與，贈與物之權利已全部移轉者，贈與人不得撤銷其贈與"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "40162905cbc1", "answer_pdf_sha1": "b681be7ebd22", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00394', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '依民法第757條關於物權法定主義之規定，物權除依法律或習慣外，不得創設。下列何者行為違反物權法 定主義？', '["設定不移轉占有之動產質權", "設定不移轉抵押不動產占有之不動產抵押權", "設定土地上一定空間之區分地上權", "移轉專有部分所有權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "40162905cbc1", "answer_pdf_sha1": "b681be7ebd22", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
