  ('generalpolice-94737317-moex-00397', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '依我國著作權法規定，有關著作的平行輸入與權利耗盡原則，下列敘述何者錯誤？', '["我國採國內耗盡原則，故即使甲為供個人觀賞之目的而於出國旅遊時於國外購買一張音樂CD光碟，連 同行李一起攜回我國，仍視為侵害著作權", "乙在我國境內購買經合法重製之書籍，得透過網路將之轉售予他人", "丙在我國境內購買經合法重製之漫畫，得經營漫畫出租店將該漫畫出租予他人", "丁在我國境內購買經合法重製之黑膠唱片，仍不得出租該唱片"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "40162905cbc1", "answer_pdf_sha1": "b681be7ebd22", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00398', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '關於法庭之友，下列敘述何者錯誤？', '["當事人或當事人以外之人民、機關或團體，均得向憲法法庭提出聲請", "聲請提出法庭之友意見時，應以書面敘明其與憲法法庭審理案件之關聯性", "依裁定許可提出專業意見或資料時，應委任代理人", "聲請提出法庭之友意見，應於憲法法庭公開聲請書、答辯書後30日內為之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "40162905cbc1", "answer_pdf_sha1": "b681be7ebd22", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00399', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '關於法定夫妻財產制，下列敘述何者錯誤？', '["夫或妻之財產分為婚前財產與婚後財產，由夫妻各自所有", "夫或妻各自管理其財產", "不能證明為婚前或婚後財產者，推定為夫妻共有", "夫妻各自對其債務負清償之責"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "40162905cbc1", "answer_pdf_sha1": "b681be7ebd22", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
